config.generatedSceneCode:
ctx.lineCap = 'round';
ctx.lineJoin = 'round';

var W = canvas.width, H = canvas.height;
var p = runtimeState.pointer || { x:-9999, y:-9999, down:false, clicked:false };
if (!runtimeState.params) runtimeState.params = {};
var params = runtimeState.params;

// Initialize required simulation variables
if (params.datasetMode == null) params.datasetMode = 1; // 1..3
if (params.softC == null) params.softC = 1; // 0.1..100
if (params.boundaryAngle == null) params.boundaryAngle = 20; // -90..90 deg
if (params.boundaryOffset == null) params.boundaryOffset = 0; // -1.5..1.5
if (params.kernelOn == null) params.kernelOn = 0; // 0/1
if (params.rbfGamma == null) params.rbfGamma = 1; // 0.1..10
if (params.stepIndex == null) params.stepIndex = 0;
if (params.dragPointId == null) params.dragPointId = '';
if (params.dragLine == null) params.dragLine = 0;
if (params.showMargins == null) params.showMargins = true;
if (params.infoOpen == null) params.infoOpen = -1;
if (params._initDone == null) params._initDone = false;
if (params._baselineSV == null) params._baselineSV = 0;
if (params._baselineErr == null) params._baselineErr = 0;
if (params._baselineBoundary == null) params._baselineBoundary = {a:params.boundaryAngle,o:params.boundaryOffset};
if (params._nonSVMoved == null) params._nonSVMoved = false;

function clamp(v,a,b){ return Math.max(a,Math.min(b,v)); }
function lerp(a,b,t){ return a+(b-a)*t; }
function inRect(mx,my,r){ return mx>=r.x && my>=r.y && mx<=r.x+r.w && my<=r.y+r.h; }
function dist2(ax,ay,bx,by){ var dx=ax-bx,dy=ay-by; return dx*dx+dy*dy; }

// Theme/palette from blueprint
var C_AXIS = '#cbd5e1';
var C_A = '#2563eb';
var C_B = '#ef4444';
var C_BOUND = '#111827';
var C_HYPER = '#7c3aed';
var C_HI = '#f59e0b';
var C_PANEL = 'rgba(250, 245, 235, 0.92)';
var C_PANEL_BORDER = 'rgba(0,0,0,0.1)';
var C_TEXT = '#1e293b';
var C_MUTED = '#64748b';
var C_GREEN = '#16A34A';
var C_RED = '#DC2626';

function rr(x,y,w,h,r,fill,stroke){
  ctx.beginPath();
  ctx.moveTo(x+r,y);
  ctx.arcTo(x+w,y,x+w,y+h,r);
  ctx.arcTo(x+w,y+h,x,y+h,r);
  ctx.arcTo(x,y+h,x,y,r);
  ctx.arcTo(x,y,x+w,y,r);
  if(fill){ ctx.fillStyle=fill; ctx.fill(); }
  if(stroke){ ctx.strokeStyle=stroke; ctx.lineWidth=1; ctx.stroke(); }
}

// Layout
var plot = { x:220, y:78, w:Math.max(420, W-540), h:Math.max(320, H-170) };
if (plot.x + plot.w > W-20) plot.w = W-20-plot.x;
if (plot.y + plot.h > H-20) plot.h = H-20-plot.y;

function toScreen(x,y){
  var sx = plot.x + (x+3)/6 * plot.w;
  var sy = plot.y + (1-(y+3)/6) * plot.h;
  return {x:sx,y:sy};
}
function toWorld(sx,sy){
  var x = ((sx-plot.x)/plot.w)*6 - 3;
  var y = (1-(sy-plot.y)/plot.h)*6 - 3;
  return {x:x,y:y};
}

// Dataset generation + draggable offsets
if (!runtimeState.dataPoints) runtimeState.dataPoints = [];
var key = params.datasetMode + '_N';
if (!params._initDone || params._lastDataKey !== key){
  runtimeState.dataPoints = [];
  var n = 26;
  for (var i=0;i<n;i++){
    var t=i/(n-1);
    if (params.datasetMode===1){
      runtimeState.dataPoints.push({id:'a'+i,c:-1,x:-2.2+1.8*t+0.12*Math.sin(i*2.1),y:0.3+1.4*t+0.14*Math.cos(i*1.3),dx:0,dy:0});
      runtimeState.dataPoints.push({id:'b'+i,c:1,x:0.2+1.7*t+0.15*Math.cos(i*1.9),y:-1.9+1.3*t+0.12*Math.sin(i*1.7),dx:0,dy:0});
    } else if (params.datasetMode===2){
      runtimeState.dataPoints.push({id:'a'+i,c:-1,x:-2.0+2.2*t+0.35*Math.sin(i*1.1),y:0.4+1.1*t+0.3*Math.cos(i*1.6),dx:0,dy:0});
      runtimeState.dataPoints.push({id:'b'+i,c:1,x:-0.3+2.1*t+0.35*Math.cos(i*1.4),y:-1.2+1.2*t+0.32*Math.sin(i*1.9),dx:0,dy:0});
    } else {
      var a = i/n*Math.PI*2;
      var r1=1.0+0.08*Math.sin(i*2.2), r2=2.0+0.1*Math.cos(i*1.7);
      runtimeState.dataPoints.push({id:'a'+i,c:-1,x:r1*Math.cos(a),y:r1*Math.sin(a),dx:0,dy:0});
      runtimeState.dataPoints.push({id:'b'+i,c:1,x:r2*Math.cos(a+0.12),y:r2*Math.sin(a+0.12),dx:0,dy:0});
    }
  }
  params._lastDataKey = key;
  params._initDone = true;
  params._nonSVMoved = false;
}
var pts = runtimeState.dataPoints;

// Boundary model (linear or kernel)
var ang = params.boundaryAngle * Math.PI/180;
var nx = Math.cos(ang), ny = Math.sin(ang); // unit normal
var b0 = params.boundaryOffset;
var marginHalf = clamp(1.15 - 0.22*Math.log(params.softC+1), 0.22, 1.25); // 1/||w|| proxy
var marginWidth = 2*marginHalf;

function scoreLinear(pt){ return nx*pt.x + ny*pt.y + b0; }
function scoreKernel(pt){
  var r2 = pt.x*pt.x + pt.y*pt.y;
  var rad = 1.52 + 0.22*Math.sin(3*Math.atan2(pt.y,pt.x)+time*0.6)*(params.rbfGamma/10);
  return r2 - rad*rad;
}

// Drag boundary handle/line
var centerW = {x:-nx*b0, y:-ny*b0};
var centerS = toScreen(centerW.x, centerW.y);
var handleR = 10;
if (p.clicked){
  if (dist2(p.x,p.y,centerS.x,centerS.y) < handleR*handleR*2.4) params.dragLine = 1;
}
if (!p.down) params.dragLine = 0;
if (p.down && params.dragLine===1 && !(params.datasetMode===3 && params.kernelOn===1)){
  var wpt = toWorld(p.x,p.y);
  params.boundaryOffset = clamp(-(nx*wpt.x + ny*wpt.y), -1.5, 1.5);
}

// Drag points
if (p.clicked){
  params.dragPointId = '';
  for (var i2=0;i2<pts.length;i2++){
    var s2 = toScreen(pts[i2].x+pts[i2].dx, pts[i2].y+pts[i2].dy);
    if (dist2(p.x,p.y,s2.x,s2.y) < 9*9){ params.dragPointId = pts[i2].id; break; }
  }
}
if (!p.down) params.dragPointId = '';
if (p.down && params.dragPointId){
  for (var i3=0;i3<pts.length;i3++) if (pts[i3].id===params.dragPointId){
    var ww = toWorld(p.x,p.y);
    pts[i3].x = clamp(ww.x,-2.9,2.9); pts[i3].y = clamp(ww.y,-2.9,2.9);
    break;
  }
}

// Metrics + support vectors
var svCount=0, errCount=0, vioCount=0;
var supportIds = {};
for (var j=0;j<pts.length;j++){
  var pt=pts[j];
  var f = (params.datasetMode===3 && params.kernelOn===1)? scoreKernel(pt):scoreLinear(pt);
  var y = pt.c;
  var hinge = 1 - y*f;
  var mis = y*f < 0;
  var vio = hinge > 0;
  var isSV = (Math.abs(hinge) < 0.15) || (hinge>0);
  if (isSV) { svCount++; supportIds[pt.id]=1; }
  if (mis) errCount++;
  if (vio) vioCount++;
}
var trainingError = errCount/Math.max(1,pts.length);

if (params.datasetMode===2 && !params._overlapInit){ params._initialViolationsCount = vioCount; params._overlapInit=true; }
if (params.datasetMode!==2) params._overlapInit=false;

// Grid/axes
ctx.strokeStyle = C_AXIS; ctx.lineWidth = 1;
for (var gx=0;gx<=6;gx++){ var X=plot.x+gx*plot.w/6; ctx.beginPath(); ctx.moveTo(X,plot.y); ctx.lineTo(X,plot.y+plot.h); ctx.stroke(); }
for (var gy=0;gy<=6;gy++){ var Y=plot.y+gy*plot.h/6; ctx.beginPath(); ctx.moveTo(plot.x,Y); ctx.lineTo(plot.x+plot.w,Y); ctx.stroke(); }
ctx.strokeStyle='rgba(100,116,139,0.7)';
var xa=toScreen(-3,0), xb=toScreen(3,0), ya=toScreen(0,-3), yb=toScreen(0,3);
ctx.beginPath(); ctx.moveTo(xa.x,xa.y); ctx.lineTo(xb.x,xb.y); ctx.stroke();
ctx.beginPath(); ctx.moveTo(ya.x,ya.y); ctx.lineTo(yb.x,yb.y); ctx.stroke();

// Boundary + margins
function drawLinear(off,style,lw,dash){
  var tx=-ny, ty=nx;
  var cx = -nx*(b0+off), cy=-ny*(b0+off);
  var p1=toScreen(cx+tx*5,cy+ty*5), p2=toScreen(cx-tx*5,cy-ty*5);
  ctx.save(); ctx.setLineDash(dash||[]); ctx.strokeStyle=style; ctx.lineWidth=lw;
  ctx.beginPath(); ctx.moveTo(p1.x,p1.y); ctx.lineTo(p2.x,p2.y); ctx.stroke(); ctx.restore();
}

if (params.datasetMode===3 && params.kernelOn===1){
  ctx.strokeStyle=C_HYPER; ctx.lineWidth=3;
  ctx.beginPath();
  for (var kk=0;kk<=220;kk++){
    var a=kk/220*Math.PI*2;
    var r=1.52 + 0.22*Math.sin(3*a+time*0.6)*(params.rbfGamma/10);
    var q=toScreen(r*Math.cos(a), r*Math.sin(a));
    if (kk===0) ctx.moveTo(q.x,q.y); else ctx.lineTo(q.x,q.y);
  }
  ctx.closePath(); ctx.stroke();
} else {
  if (params.showMargins){
    drawLinear(0,'rgba(245,158,11,0.10)',10+10*Math.sin(time*0.8)*0.05,[]);
    drawLinear(marginHalf,'rgba(17,24,39,0.7)',2,[6,6]);
    drawLinear(-marginHalf,'rgba(17,24,39,0.7)',2,[6,6]);
  }
  drawLinear(0,C_HYPER,3,[]);
  // draggable handle
  ctx.beginPath(); ctx.arc(centerS.x,centerS.y,7+1.2*Math.sin(time*5),0,Math.PI*2);
  ctx.fillStyle='rgba(245,158,11,0.95)'; ctx.fill();
  ctx.strokeStyle='white'; ctx.lineWidth=2; ctx.stroke();
}

// Draw points
for (var m=0;m<pts.length;m++){
  var d=pts[m];
  var s=toScreen(d.x,d.y);
  var f2=(params.datasetMode===3 && params.kernelOn===1)?scoreKernel(d):scoreLinear(d);
  var y2=d.c, hinge2=1-y2*f2;
  var mis2=y2*f2<0, vio2=hinge2>0, isSV2=(Math.abs(hinge2)<0.15)||hinge2>0;
  var r0=isSV2?6.8:5.2;
  if (isSV2){ r0 += 0.6*Math.sin(time*6+m); }
  ctx.beginPath(); ctx.arc(s.x,s.y,r0,0,Math.PI*2);
  ctx.fillStyle = d.c<0?C_A:C_B; ctx.fill();
  ctx.lineWidth = isSV2?2.8:1.3;
  ctx.strokeStyle = isSV2?C_HI:'rgba(15,23,42,0.45)';
  ctx.stroke();
  if (mis2){
    ctx.strokeStyle=C_HI; ctx.lineWidth=2;
    ctx.beginPath(); ctx.moveTo(s.x-5,s.y-5); ctx.lineTo(s.x+5,s.y+5); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(s.x+5,s.y-5); ctx.lineTo(s.x-5,s.y+5); ctx.stroke();
  } else if (vio2){
    ctx.beginPath(); ctx.arc(s.x,s.y,r0+4,0,Math.PI*2);
    ctx.strokeStyle='rgba(245,158,11,0.45)'; ctx.lineWidth=1.5; ctx.stroke();
  }
}

// Title/labels
ctx.textAlign='center';
ctx.fillStyle=C_TEXT; ctx.font='600 20px system-ui, sans-serif';
ctx.fillText('How SVMs Find the Best Separator', W*0.5, 34);
ctx.textAlign='left';
ctx.fillStyle=C_TEXT; ctx.font='11px system-ui, sans-serif';
ctx.fillText('x1', plot.x+plot.w-16, toScreen(3,0).y-6);
ctx.fillText('x2', toScreen(0,0).x+6, plot.y+12);
ctx.fillStyle=C_MUTED; ctx.font='italic 13px Georgia, serif';
ctx.fillText('Decision boundary', plot.x+14, plot.y-10);
ctx.fillText('Margins', plot.x+170, plot.y-10);
ctx.fillText('Only support vectors affect the boundary.', plot.x+14, plot.y+plot.h+18);

// Controls panel top-left
var cp={x:16,y:16,w:192,h:360}; rr(cp.x,cp.y,cp.w,cp.h,12,C_PANEL,C_PANEL_BORDER);
ctx.textAlign='left'; ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif';
ctx.fillText('SVM CONTROLS',cp.x+14,cp.y+18);

function button(x,y,w,h,label,active){ rr(x,y,w,h,6,active?'rgba(37,99,235,0.16)':'rgba(255,255,255,0.6)',C_PANEL_BORDER); ctx.textAlign='center'; ctx.fillStyle=C_TEXT; ctx.font='11px system-ui, sans-serif'; ctx.fillText(label,x+w/2,y+h/2+4); ctx.textAlign='left'; return {x:x,y:y,w:w,h:h}; }
function slider(x,y,w,label,key,min,max){
  ctx.textAlign='left'; ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.fillText(label,x,y);
  var ty=y+8; rr(x,ty,w,6,4,'rgba(148,163,184,0.35)',null);
  var t=clamp((params[key]-min)/(max-min),0,1); rr(x,ty,w*t,6,4,'rgba(37,99,235,0.9)',null);
  var hx=x+w*t; ctx.beginPath(); ctx.arc(hx,ty+3,6,0,Math.PI*2); ctx.fillStyle='#fff'; ctx.fill(); ctx.strokeStyle='rgba(37,99,235,0.9)'; ctx.lineWidth=2; ctx.stroke();
  if (p.down && p.x>=x-8 && p.x<=x+w+8 && p.y>=ty-8 && p.y<=ty+14){ params[key]=min+clamp((p.x-x)/w,0,1)*(max-min); }
  ctx.fillStyle=C_TEXT; ctx.font='700 11px ui-monospace, monospace'; ctx.fillText((Math.round(params[key]*100)/100)+'',x+w-44,y);
}

var y0=cp.y+34;
ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.fillText('DATASET',cp.x+14,y0);
var d1=button(cp.x+14,y0+8,52,24,'1',params.datasetMode===1);
var d2=button(cp.x+72,y0+8,52,24,'2',params.datasetMode===2);
var d3=button(cp.x+130,y0+8,48,24,'3',params.datasetMode===3);
if (p.clicked && inRect(p.x,p.y,d1)) params.datasetMode=1;
if (p.clicked && inRect(p.x,p.y,d2)) params.datasetMode=2;
if (p.clicked && inRect(p.x,p.y,d3)) params.datasetMode=3;

slider(cp.x+14,y0+52,164,'SOFT-MARGIN C','softC',0.1,100);
slider(cp.x+14,y0+92,164,'BOUNDARY ANGLE','boundaryAngle',-90,90);
slider(cp.x+14,y0+132,164,'BOUNDARY OFFSET','boundaryOffset',-1.5,1.5);
slider(cp.x+14,y0+172,164,'KERNEL MODE (0/1)','kernelOn',0,1);
if (params.datasetMode===3) slider(cp.x+14,y0+212,164,'RBF GAMMA','rbfGamma',0.1,10);

var resetStep=button(cp.x+14,cp.y+324,78,24,'RESET STEP',false);
var resetData=button(cp.x+100,cp.y+324,78,24,'RESET DATA',false);
if (p.clicked && inRect(p.x,p.y,resetStep)){ params.stepIndex=0; }
if (p.clicked && inRect(p.x,p.y,resetData)){ params._initDone=false; }

// Metrics panel
var mp={x:16,y:386,w:192,h:118}; rr(mp.x,mp.y,mp.w,mp.h,12,C_PANEL,C_PANEL_BORDER);
ctx.textAlign='left'; ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.fillText('LIVE METRICS',mp.x+14,mp.y+18);
ctx.font='700 12px ui-monospace, monospace';
ctx.fillText('MARGIN WIDTH: '+(Math.round(marginWidth*100)/100),mp.x+14,mp.y+40);
ctx.fillText('# SUPPORT VEC: '+svCount,mp.x+14,mp.y+60);
ctx.fillText('TRAINING ERROR: '+(Math.round(trainingError*1000)/10)+'%',mp.x+14,mp.y+80);
ctx.fillText('# VIOLATIONS: '+vioCount,mp.x+14,mp.y+100);

// Legend top-right
var lg={x:W-300,y:16,w:284,h:96}; rr(lg.x,lg.y,lg.w,lg.h,12,C_PANEL,C_PANEL_BORDER);
ctx.textAlign='left'; ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.fillText('LEGEND',lg.x+14,lg.y+18);
ctx.fillStyle=C_A; ctx.beginPath(); ctx.arc(lg.x+22,lg.y+38,5,0,Math.PI*2); ctx.fill(); ctx.fillStyle=C_TEXT; ctx.font='11px system-ui, sans-serif'; ctx.fillText('CLASS A',lg.x+34,lg.y+42);
ctx.fillStyle=C_B; ctx.beginPath(); ctx.arc(lg.x+22,lg.y+58,5,0,Math.PI*2); ctx.fill(); ctx.fillStyle=C_TEXT; ctx.fillText('CLASS B',lg.x+34,lg.y+62);
ctx.strokeStyle=C_HI; ctx.lineWidth=2; ctx.beginPath(); ctx.arc(lg.x+22,lg.y+78,7,0,Math.PI*2); ctx.stroke(); ctx.fillStyle=C_TEXT; ctx.fillText('SUPPORT / VIOLATION / MISCLASS',lg.x+34,lg.y+82);

// SCAFFOLD STEP 1: Select Dataset 1 (linearly separable) and drag the boundary until no points are misclassified.
// SCAFFOLD STEP 2: Turn on Show Margins and drag the boundary to maximize the margin width.
// SCAFFOLD STEP 3: Observe support vectors; move a non-support point far away and boundary stays stable.
// SCAFFOLD STEP 4: Switch to Dataset 2 and adjust C from low to high; watch violations/error/margin.
// SCAFFOLD STEP 5: Switch to Dataset 3, enable kernel mode, vary gamma.
var targetMaxMargin = 2.2;
var supportVectorsStable = params._nonSVMoved ? true : false;
var steps=[
  {instruction:'Select Dataset 1 and drag boundary until no points are misclassified.',concept:'A separating hyperplane classifies by which side of the line a point falls on.',done:(params.datasetMode===1 && trainingError===0)},
  {instruction:'Keep margins visible and adjust to maximize margin width.',concept:'SVM seeks the widest safety corridor between classes.',done:(params.datasetMode===1 && marginWidth>=targetMaxMargin*0.95)},
  {instruction:'Move a clearly non-support point; boundary should barely change.',concept:'Only support vectors constrain the optimal boundary.',done:supportVectorsStable},
  {instruction:'Switch to Dataset 2 and increase C; compare violations and margin.',concept:'Soft margin trades off margin size versus violations.',done:(params.datasetMode===2 && params.softC>=50 && vioCount<=(params._initialViolationsCount||vioCount))},
  {instruction:'Use Dataset 3, enable kernel mode, vary gamma low/high.',concept:'Kernel trick yields nonlinear input-space boundaries via simpler transformed-space separation.',done:(params.datasetMode===3 && params.kernelOn>=0.5 && (params.rbfGamma<=0.3 || params.rbfGamma>=5))}
];
params.stepIndex = clamp(Math.round(params.stepIndex),0,steps.length-1);
var st=steps[params.stepIndex];

var sp={x:W-300,y:120,w:284,h:244}; rr(sp.x,sp.y,sp.w,sp.h,12,C_PANEL,C_PANEL_BORDER);
ctx.textAlign='left'; ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.fillText('SCAFFOLDED STEPS',sp.x+14,sp.y+18);
ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif'; ctx.fillText('Step '+(params.stepIndex+1)+' / '+steps.length,sp.x+14,sp.y+36);
function wrap(txt,x,y,w,lh,font,color){ ctx.textAlign='left'; ctx.font=font; ctx.fillStyle=color; var words=txt.split(' '), line='', yy=y; for(var i=0;i<words.length;i++){ var t=line+words[i]+' '; if(ctx.measureText(t).width>w && i>0){ ctx.fillText(line,x,yy); line=words[i]+' '; yy+=lh;} else line=t;} ctx.fillText(line,x,yy); return yy; }
wrap('INSTRUCTION: '+st.instruction,sp.x+14,sp.y+56,sp.w-28,16,'700 11px system-ui, sans-serif',C_TEXT);
wrap('Concept: '+st.concept,sp.x+14,sp.y+126,sp.w-28,18,'italic 14px Georgia, serif',C_MUTED);
ctx.textAlign='left'; ctx.font='700 12px ui-monospace, monospace'; ctx.fillStyle=st.done?C_GREEN:C_RED; ctx.fillText(st.done?'Condition met':'Condition not met',sp.x+14,sp.y+198);
var lb=button(sp.x+14,sp.y+208,34,24,'←',false), rb=button(sp.x+56,sp.y+208,34,24,'→',false);
if (p.clicked && inRect(p.x,p.y,lb)) params.stepIndex = clamp(params.stepIndex-1,0,steps.length-1);
if (p.clicked && inRect(p.x,p.y,rb)) params.stepIndex = clamp(params.stepIndex+1,0,steps.length-1);

// Kernel inset
if (params.datasetMode===3 && params.kernelOn>=0.5){
  var ki={x:W-300,y:370,w:284,h:132}; rr(ki.x,ki.y,ki.w,ki.h,12,C_PANEL,C_PANEL_BORDER);
  ctx.textAlign='left'; ctx.fillStyle=C_TEXT; ctx.font='10px system-ui, sans-serif'; ctx.fillText('FEATURE SPACE INSET',ki.x+14,ki.y+18);
  ctx.strokeStyle='rgba(100,116,139,0.45)'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.arc(ki.x+76,ki.y+75,22,0,Math.PI*2); ctx.stroke();
  ctx.beginPath(); ctx.arc(ki.x+76,ki.y+75,44,0,Math.PI*2); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(ki.x+150,ki.y+30); ctx.lineTo(ki.x+150,ki.y+112); ctx.stroke();
  ctx.strokeStyle=C_HYPER; ctx.lineWidth=2.5;
  var wig = 4 + params.rbfGamma*0.8;
  ctx.beginPath(); ctx.moveTo(ki.x+150,ki.y+72);
  for(var qx=0;qx<=108;qx++){ ctx.lineTo(ki.x+150+qx, ki.y+72 + Math.sin(qx*0.08+time)*wig*0.05); }
  ctx.stroke();
  ctx.fillStyle=C_MUTED; ctx.font='11px system-ui, sans-serif';
  ctx.fillText('In feature space, separation can be linear.',ki.x+14,ki.y+124);
}

// Info points (clickable labels)
var infoTargets=[];
function infoLabel(label,ex,x,y){
  ctx.textAlign='left'; ctx.font='11px system-ui, sans-serif'; ctx.fillStyle='rgba(245,158,11,0.95)';
  ctx.fillText(label,x,y);
  var w=ctx.measureText(label).width;
  infoTargets.push({x:x-2,y:y-11,w:w+4,h:14,label:label,explanation:ex});
